var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"우선 네 역량을 확인해볼 거야.","JPN":"まず、あなたの力を確認するわね。","ENG":"First, I'll check your competency.","TWN":"首先會確認你的能力。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"저기 놓여있는 캔을 네 능력으로 공격해볼래?","JPN":"あなたの能力であそこにある缶を攻撃してくれる？","ENG":"How about attacking that can over there with your ability?","TWN":"用你的能力攻擊那邊的罐子吧。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"좋아요.","JPN":"はい。","ENG":"Okay.","TWN":"好的。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"으음…!","JPN":"ふうっ……！","ENG":"Mm...!","TWN":"嗯……！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"식물을 순식간에 자라게 하다니. 멋진 능력이네.","JPN":"瞬時に植物を育てるとは。素敵な能力ね。","ENG":"Making plants grow in an instant. What an amazing ability!","TWN":"能讓植物瞬間生長，真是了不起的能力啊。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"헤헤-","JPN":"へへー","ENG":"Hehe.","TWN":"嘿嘿——"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"하지만 덩굴로 캔을 감싸는 건 공격이라 할 수 없어.","JPN":"でもツタで缶を包むのは攻撃とは言えないわ。","ENG":"But wrapping the can with vines isn't exactly an attack.","TWN":"但是用藤蔓纏繞罐子不能算是攻擊。"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"가장 싫어하는 사람을 떠올리면서 그 사람을 해친다는 느낌으로 공격해봐.","JPN":"一番嫌いな人を思い出して、その人を殴る感覚で攻撃してみて。","ENG":"Think of the person you hate the most and attack as if you're hurting that person.","TWN":"想像你最討厭的人，然後帶著傷害那個人的想法去攻擊吧。"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"으음…","JPN":"うーん……","ENG":"Mm...","TWN":"嗯……"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그치만 싫어하는 사람이 없는 걸요?","JPN":"でも、嫌いな人なんていないんですよ？","ENG":"But I don't hate anyone.","TWN":"可是我沒有討厭的人啊。"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"없다고…? 진짜?","JPN":"いない……？　本当？","ENG":"None...? Really?","TWN":"沒有？真的嗎？"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"미안 미안. 난 <color=#ffd34c>학교</color>에서 이런 식으로 배웠거든.","JPN":"ごめんごめん。私は<color=#ffd34c>学校</color>でこういう風に習ったから。","ENG":"Sorry, sorry. I learned this kind of thing back at <color=#ffd34c>school</color>.","TWN":"抱歉抱歉。我在[學校]裡是這樣學的。"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그럼 이건 어때? 저걸 침식체라고 생각해보는 거야.","JPN":"それじゃあ、これはどう？　あれを侵食体だと思うの。","ENG":"How about this? Try imagining that as a C.O.","TWN":"那這個怎麼樣？想像它是侵蝕體。"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"침식체…","JPN":"侵食体……","ENG":"C.O...","TWN":"侵蝕體……"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"해볼게요.","JPN":"やってみます。","ENG":"I'll try.","TWN":"我會試試的。"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"하앗!","JPN":"はあっ！","ENG":"Hah!","TWN":"哈啊！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"가시덩굴이구나.","JPN":"茨のツタ、ね。","ENG":"A thorny vine.","TWN":"是荊棘啊。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"이런 방법을 떠올리다니 제법이네. 식물이라도 이런 종류라면 타격을 줄 수 있겠는걸?","JPN":"こんな方法を思いつくなんてやるじゃない。植物でもこの種類ならダメージも与えられそうよ？","ENG":"To come up with a method like this, you're pretty clever. A plant of this kind could definitely deal a blow!","TWN":"能想到這種方法，真不錯。如果是這種植物的話，應該能算是攻擊吧？"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"캔이 산산이 찢겼어. 사람이었다면 분명 즉사네.","JPN":"缶がバラバラになっちゃった。たぶん人だったら即死ね。","ENG":"The can's completely shredded. If it were a person, that person would be dead for sure.","TWN":"罐子被打爛咧。如果是人的話，肯定會當場死亡。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"힉…! 그러려던 건 아니었어요!","JPN":"ひっ……！　そのつもりはなかったんです！","ENG":"Yikes...! That's not what I meant to do!","TWN":"唔！我真的不是那個意思！"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L39_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"아하하, 말이 그렇다는 거지.","JPN":"あはは、言葉のあやよ。","ENG":"Ah hah hah, I was just making a point.","TWN":"啊哈哈，我只是說說而已。"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"하지만 정말로 필요하다면- 언젠가 그 능력이 사람을 향하게 될 수도 있을 거야.","JPN":"でも状況次第では、いつかその力で人を攻撃しなければならない時も来るはずよ。","ENG":"But if it really becomes necessary, someday, that power might be directed at people.","TWN":"但是如果真的有必要的話，或許有一天那能力可能會對準人類。"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};